function ListOnLesson({data}) {
  return (
    <div className="list-on-lesson">
      <div>
        <span>{data.name}</span>
        <p>{data.time}</p>
      </div>
      <ul>
        {data.material.map((item,index)=>(
          <div key={index}>
            <span>
              {item.name}
            </span>
            <p>
              {item.time}
            </p>
          </div>
        ))}
      </ul>
    </div>
  );
}

export default ListOnLesson;
